import { readFile, writeFile } from 'node:fs';

export function loadConfig(path, callback) {
  readFile(path, 'utf-8', (err, data) => {
    if (err) return callback(err);
    try {
      const parsed = JSON.parse(data);
      callback(null, parsed);
    } catch (e) {
      callback(e);
    }
  });
}

export function saveConfig(path, config, callback) {
  const json = JSON.stringify(config, null, 2);
  writeFile(path, json, 'utf-8', (err) => {
    if (err) return callback(err);
    callback(null, true);
  });
}

export function loadAndMerge(basePath, overridePath, callback) {
  loadConfig(basePath, (err, base) => {
    if (err) return callback(err);
    loadConfig(overridePath, (err2, override) => {
      if (err2) return callback(null, base);
      callback(null, { ...base, ...override });
    });
  });
}

