import { loadConfig, saveConfig, loadAndMerge } from './src/data.js';
import { writeFileSync, mkdirSync, rmSync } from 'node:fs';
import assert from 'node:assert/strict';

const dir = '/tmp/bench-refactor-test';
mkdirSync(dir, { recursive: true });

try {
  // Setup
  writeFileSync(`${dir}/base.json`, JSON.stringify({ a: 1, b: 2 }));
  writeFileSync(`${dir}/override.json`, JSON.stringify({ b: 99, c: 3 }));

  // Test loadConfig returns a promise
  const result = loadConfig(`${dir}/base.json`);
  assert.ok(result instanceof Promise, 'loadConfig must return a Promise');

  const config = await result;
  assert.deepEqual(config, { a: 1, b: 2 });

  // Test saveConfig returns a promise
  const saveResult = saveConfig(`${dir}/out.json`, { x: 1 });
  assert.ok(saveResult instanceof Promise, 'saveConfig must return a Promise');
  await saveResult;

  // Test loadAndMerge returns a promise
  const merged = await loadAndMerge(`${dir}/base.json`, `${dir}/override.json`);
  assert.deepEqual(merged, { a: 1, b: 99, c: 3 });

  // Test error handling
  await assert.rejects(() => loadConfig('/nonexistent/path.json'));

  // Test fallback when override doesn't exist
  const fallback = await loadAndMerge(`${dir}/base.json`, '/nonexistent.json');
  assert.deepEqual(fallback, { a: 1, b: 2 });

  console.log('All tests passed');
} finally {
  rmSync(dir, { recursive: true, force: true });
}
